import React, { useState } from 'react';
import ImportDataSidebar from './ImportDataSidebar'; // Importing the sidebar component
import './ChatBox.css';
import SideNav from './SideNav';
import { useNavigate } from 'react-router-dom'; // Import useNavigate from react-router-dom

function ChatBox() {
  const [userStory, setUserStory] = useState('');
  const [messages, setMessages] = useState([]);
  const [isSidebarVisible, setIsSidebarVisible] = useState(false);
  const [jiraData, setJiraData] = useState([]); // Data fetched from Jira
  const [isAuthenticated, setIsAuthenticated] = useState(true); // Manage login state
  
  const navigate = useNavigate(); // Initialize the navigate function

  // Handle logout (simulate logout)
  const logout = () => {
    setIsAuthenticated(false);
    navigate('/Login'); // Navigate to the Login page after logout
  };

  // Handle message input from user
  const handleMessageChange = (e) => {
    setUserStory(e.target.value);
  };

  // Handle sending the user story message (chat-like)
  const handleSendMessage = () => {
    if (userStory.trim()) {
      setMessages([...messages, { text: userStory, isUserMessage: true }]);
      setUserStory('');

      // After sending the message, call the generateTestCases function
      generateTestCases(userStory);  // Call the function to generate test cases
    }
  };

  // Function to send user story and get generated test cases
  const generateTestCases = async (userStory) => {
    try {
      const response = await fetch('/api/UserStoryDescription/GenerateTestCases', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'apiKey': 'AIzaSyDy8skxKpN76tUGmw_7CuiFo_aRiP5nj5s', // Replace with your API key if needed
        },
        body: JSON.stringify({ userStory }), // Send userStory in body
      });

      if (!response.ok) {
        throw new Error('Failed to generate test cases');
      }

      const data = await response.json();
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: `Generated test cases:\n${data}`, isUserMessage: false },
      ]);
    } catch (error) {
      console.error('Error generating test cases:', error);
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: 'Error generating test cases. Please try again later.', isUserMessage: false },
      ]);
    }
  };

  // Fetch data from Jira
  const handleImportData = async () => {
    try {
      const response = await fetch('https://shivnarayan2799.atlassian.net/browse/SCRUM-2', {
        method: 'GET',
        headers: {
          'Authorization': `Basic ${btoa('shivnarayan2799@gmail.com:ATATT3xFfGF0vqs5wPxfeJCQpqgxhQPGLmbaTsJHruENLlT0bDv35-1tqqKZPcNHEIRWhrG3J8y0Ziy3QP3kLkWNBczrWIZQHJcpydRI4aFf783mn2NvKsBK_EJ6sg-4zlxVVDOiW20Pd6WRS3hkJrfg_r7YeRSndoLwGFRBr3ZatuhWIdSFApA=1D1D3CF4')}`, // Basic auth with base64 encoded email and API token
          'Accept': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error('Failed to fetch data from Jira');
      }

      const data = await response.json();
      const stories = data.issues.map(issue => ({
        id: issue.id,
        story: issue.fields.summary, // Adjust based on Jira response structure
      }));
      
      setJiraData(stories);
      setIsSidebarVisible(true); // Show the sidebar after importing data
    } catch (error) {
      console.error('Error fetching Jira data:', error);
    }
  };

  // Handle selecting a user story from the sidebar
  const handleSelectUserStory = (story) => {
    setUserStory(story); // Set the selected story in the chat box
  };

  // Handle closing the sidebar
  const handleCloseSidebar = () => {
    setIsSidebarVisible(false); // Close the sidebar
  };

  return (
    <div className="chat-container">
      {/* Render SideNav only if authenticated */}
      {isAuthenticated && <SideNav logout={logout} />} {/* Pass logout to SideNav */}

      {/* Chat box UI */}
      <div className="chat-box">
        <div className="chat-box-messages">
          {messages.map((message, index) => (
            <div
              key={index}
              className={`message ${message.isUserMessage ? 'user-message' : 'bot-message'}`}
            >
              {message.text}
            </div>
          ))}
        </div>
        <div className="chat-input-container">
          <textarea
            value={userStory}
            onChange={handleMessageChange}
            placeholder="Enter your user story here..."
            rows="4"
          />
          <button onClick={handleSendMessage}>Send</button>
        </div>
      </div>

      {/* Sidebar for importing Jira data */}
      {isSidebarVisible && (
        <ImportDataSidebar
          jiraData={jiraData}
          onSelectUserStory={handleSelectUserStory}
          onClose={handleCloseSidebar} // Pass close handler to sidebar
        />
      )}

      {/* Button to import data from Jira */}
      <button className="import-btn" onClick={handleImportData}>
        Import Data from Jira
      </button>
    </div>
  );
}

export default ChatBox;
